glsl3.vert:
precision highp float;
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
#if USE_LOCAL
  layout(std140) uniform CCLocal {
    highp mat4 cc_matWorld;
    highp mat4 cc_matWorldIT;
    highp vec4 cc_lightingMapUVParam;
    highp vec4 cc_localShadowBias;
    highp vec4 cc_reflectionProbeData1;
    highp vec4 cc_reflectionProbeData2;
    highp vec4 cc_reflectionProbeBlendData1;
    highp vec4 cc_reflectionProbeBlendData2;
  };
#endif
in vec3 a_position;
in vec2 a_texCoord;
out vec2 uv;
#if USE_LOCAL
  in vec4 a_color;
  out vec4 v_color;
#endif
vec4 vert() {
  vec4 pos = vec4(a_position, 1);
  #if USE_LOCAL
    pos = cc_matWorld * pos;
    v_color = a_color;
  #endif
  pos = cc_matViewProj * pos;
  uv = a_texCoord;
  return pos;
}
void main() { gl_Position = vert(); }

glsl3.frag:
precision highp float;
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
in vec2 uv;
in vec4 v_color;
layout(std140) uniform UBO {
  vec4 snowColor;
  float snowSpeed;
  float snowDensity;
  float snowSize;
  float windStrength;
  float snowSwing;
};
float random2D(vec2 st) {
  return fract(sin(dot(st.xy, vec2(12.9898, 78.233))) * 43758.5453123);
}
float circle(vec2 uv, float size) {
  float d = length(uv);
  return 1.0 - smoothstep(size, size + 0.001, d);
}
float createSnowflake(vec2 uv, float time) {
  float totalSnow = 0.0;
  float wind = windStrength * uv.y + snowSwing * sin(time * 1.2 + uv.y * 4.0);
  vec2 p = uv + vec2(wind, 0.0);
  vec2 grid = p * snowDensity;
  vec2 id = floor(grid);
  vec2 subuv = fract(grid) - 0.5;
  float rand = random2D(id);
  float rand2 = random2D(id * 1.7 + vec2(23.0, 73.0));
  float fall = fract(time * snowSpeed * (0.4 + rand * 0.8) + rand2);
  float alive = step(0.05, rand2);
  float finalSize = snowSize * (0.5 + rand * 1.0);
  float flake = circle(subuv, finalSize) * alive;
  totalSnow += flake * (1.0 - fall * 0.4);
  return clamp(totalSnow, 0.0, 1.0);
}
vec4 frag() {
  float time = cc_time.x;
  float snow = createSnowflake(uv, time);
  return snowColor * snow;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

